import 'package:flutter/material.dart';import 'package:flutter_riverpod/flutter_riverpod.dart';import 'package:go_router/go_router.dart';import '../../../config/brand_config.dart';import '../../../config/design_tokens.dart';import '../../parking/data/providers.dart';import '../../parking/presentation/parking_card.dart';import '../../search/presentation/search_controller.dart';import '../../search/presentation/search_sheet.dart';import 'map_canvas.dart';
class DiscoveryScreen extends ConsumerStatefulWidget{final bool results;const DiscoveryScreen({super.key,this.results=false});@override ConsumerState<DiscoveryScreen> createState()=>_D();}
class _D extends ConsumerState<DiscoveryScreen>{bool resolving=false;String status='';@override Widget build(BuildContext c){final desktop=MediaQuery.sizeOf(c).width>T.desktop;final q=ref.watch(searchProvider);final results=ref.watch(parkingResultsProvider);final selected=ref.watch(selectedParkingIdProvider)??results.firstOrNull?.id;return Scaffold(body:Stack(children:[Row(children:[if(desktop)_Panel(results:widget.results),Expanded(child:Stack(children:[const FreiraumMap(),Positioned(top:MediaQuery.paddingOf(c).top+12,left:desktop?20:16,right:desktop?20:16,child:_SearchCapsule(onTap:()=>_openSearch(c),text:q.destination?.name??'Wohin möchtest du?',sub:q.destination==null?'Heute · 18:00–22:00':q.summary())),Positioned(right:16,top:MediaQuery.paddingOf(c).top+86,child:Column(children:[_Round(icon:Icons.my_location,label:'Standort verwenden',onTap:()=>_snack(c,'Demo-Standort Frankfurt verwendet. Keine Hintergrund-Ortung.')),_Round(icon:Icons.person,label:'Profil öffnen',onTap:()=>_profile(c))])),if(!desktop)Positioned(left:0,right:0,bottom:0,child:_Bottom(resultsMode:widget.results))]))]),if(resolving)Center(child:Container(padding:const EdgeInsets.all(24),decoration:BoxDecoration(color:T.ink,borderRadius:BorderRadius.circular(28),boxShadow:T.shadow),child:Text(status,style:const TextStyle(color:Colors.white,fontWeight:FontWeight.w900,fontSize:18)))),Positioned(left:desktop?24:16,bottom:desktop?18:6,child:_Nav(onPreview:(t)=>_preview(c,t,'Diese Route wird in einer nächsten Iteration voll ausgebaut.')))]));}
Future<void> _openSearch(BuildContext c)async{await showModalBottomSheet(context:c,isScrollControlled:true,backgroundColor:T.porcelain,builder:(_)=>SearchSheet(onSubmit:()async{Navigator.pop(c);await _resolve();if(mounted)context.go('/search');}));}
Future<void> _resolve()async{setState(()=>resolving=true);for(final s in ['Verfügbarkeit wird geprüft','12 passende Stellplätze','Ankunft ist vorbereitet']){setState(()=>status=s);await Future.delayed(MediaQuery.disableAnimationsOf(context)?Duration.zero:const Duration(milliseconds:360));}setState(()=>resolving=false);}void _snack(BuildContext c,String m)=>ScaffoldMessenger.of(c).showSnackBar(SnackBar(content:Text(m)));void _profile(BuildContext c)=>showModalBottomSheet(context:c,builder:(_)=>Padding(padding:const EdgeInsets.all(24),child:Column(mainAxisSize:MainAxisSize.min,crossAxisAlignment:CrossAxisAlignment.start,children:[const Text('Profil',style:TextStyle(fontSize:24,fontWeight:FontWeight.w900)),const Text('Demo-Profil: Buchungen, Favoriten und Fahrzeugverwaltung folgen. Demo-Daten können zurückgesetzt werden.'),const SizedBox(height:12),FilledButton(onPressed:(){ref.read(searchProvider.notifier).reset();Navigator.pop(c);_snack(c,'Demo zurückgesetzt');},child:const Text('Demo zurücksetzen'))])));void _preview(BuildContext c,String t,String m)=>showModalBottomSheet(context:c,builder:(_)=>Padding(padding:const EdgeInsets.all(24),child:Column(mainAxisSize:MainAxisSize.min,crossAxisAlignment:CrossAxisAlignment.start,children:[Text(t,style:const TextStyle(fontSize:24,fontWeight:FontWeight.w900)),Text(m),const SizedBox(height:12),FilledButton(onPressed:()=>Navigator.pop(c),child:const Text('Verstanden'))])));}
class _Panel extends ConsumerWidget{final bool results;const _Panel({required this.results});@override Widget build(BuildContext c,WidgetRef ref){final q=ref.watch(searchProvider);final r=ref.watch(parkingResultsProvider);return Container(width:430,padding:EdgeInsets.fromLTRB(20,MediaQuery.paddingOf(c).top+16,20,16),color:T.porcelain,child:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[const Text(BrandConfig.name,style:TextStyle(fontSize:30,fontWeight:FontWeight.w900,letterSpacing:2)),const Text(BrandConfig.tagline),if(results)...[_Filters(),Text('${r.length} passende Stellplätze · Demo-Daten',style:const TextStyle(fontWeight:FontWeight.w800)),Text(q.summary())],Expanded(child:ListView(children:r.map((s)=>ParkingCard(s:s,q:q,selected:ref.watch(selectedParkingIdProvider)==s.id,onTap:()=>ref.read(selectedParkingIdProvider.notifier).state=s.id)).toList()))]));}}
class _Bottom extends ConsumerWidget{final bool resultsMode;const _Bottom({required this.resultsMode});@override Widget build(BuildContext c,WidgetRef ref){final r=ref.watch(parkingResultsProvider);final q=ref.watch(searchProvider);return Container(height:resultsMode?360:230,padding:const EdgeInsets.fromLTRB(16,12,16,70),decoration:BoxDecoration(color:T.porcelain,borderRadius:const BorderRadius.vertical(top:Radius.circular(28)),boxShadow:T.shadow),child:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[Container(width:44,height:4,decoration:BoxDecoration(color:T.muted,borderRadius:BorderRadius.circular(9))),if(resultsMode)_Filters(),Text('${r.length} Stellplätze · Demo-Daten',style:const TextStyle(fontWeight:FontWeight.w900)),Expanded(child:ListView(scrollDirection:Axis.horizontal,children:r.map((s)=>SizedBox(width:330,child:ParkingCard(s:s,q:q,selected:ref.watch(selectedParkingIdProvider)==s.id,onTap:()=>ref.read(selectedParkingIdProvider.notifier).state=s.id))).toList()))]));}}
class _Filters extends ConsumerWidget{@override Widget build(BuildContext c,WidgetRef ref){final q=ref.watch(searchProvider);const fs={'covered':'Überdacht','ev':'E-Laden','accessible':'Barrierearm','instant':'Sofortbuchung','fit':'Fahrzeug passt'};return Wrap(spacing:6,children:[DropdownButton<String>(value:q.sort,items:['Empfohlen','Preis','Fußweg'].map((s)=>DropdownMenuItem(value:s,child:Text(s))).toList(),onChanged:(v)=>ref.read(searchProvider.notifier).sort(v!)),...fs.entries.map((e)=>FilterChip(label:Text(e.value),selected:q.filters.contains(e.key),onSelected:(_)=>ref.read(searchProvider.notifier).toggle(e.key))) ]);}}
class _SearchCapsule extends StatelessWidget{final VoidCallback onTap;final String text,sub;const _SearchCapsule({required this.onTap,required this.text,required this.sub});@override Widget build(BuildContext c)=>Semantics(button:true,label:'Suche öffnen',child:InkWell(onTap:onTap,borderRadius:BorderRadius.circular(24),child:Container(padding:const EdgeInsets.all(16),decoration:BoxDecoration(color:T.surface,borderRadius:BorderRadius.circular(24),boxShadow:T.shadow),child:Row(children:[const Icon(Icons.search),const SizedBox(width:12),Expanded(child:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[Text(text,style:const TextStyle(fontWeight:FontWeight.w900)),Text(sub)])),const Icon(Icons.tune)]))));}
